glsl3.vert:
precision highp float;
uniform CCGlobal {
  mat4 cc_matView;
  mat4 cc_matViewInv;
  mat4 cc_matProj;
  mat4 cc_matProjInv;
  mat4 cc_matViewProj;
  mat4 cc_matViewProjInv;
  vec4 cc_cameraPos;
  vec4 cc_time;
  mediump vec4 cc_screenSize;
  mediump vec4 cc_screenScale;
};
uniform CCLocal {
  mat4 cc_matWorld;
  mat4 cc_matWorldIT;
};
in vec3 a_position;
in vec4 a_color;
out vec4 v_color;
in vec2 a_uv0;
out vec2 v_uv0;
void main() {
  vec4 pos = vec4(a_position, 1);
  pos = cc_matViewProj * pos;
  v_uv0 = a_uv0;
  v_color = a_color;
  gl_Position = pos;
}

glsl3.frag:
precision highp float;
uniform CCGlobal {
  mat4 cc_matView;
  mat4 cc_matViewInv;
  mat4 cc_matProj;
  mat4 cc_matProjInv;
  mat4 cc_matViewProj;
  mat4 cc_matViewProjInv;
  vec4 cc_cameraPos;
  vec4 cc_time;
  mediump vec4 cc_screenSize;
  mediump vec4 cc_screenScale;
};
uniform CCLocal {
  mat4 cc_matWorld;
  mat4 cc_matWorldIT;
};
in vec4 v_color;
in vec2 v_uv0;
in vec2 v_uv1;
uniform sampler2D texture;
float Remap01(float a, float b, float t) {
  return (t-a) / (b-a);
}
float Remap(float a, float b, float c, float d, float t) {
  return Remap01(a, b, t) * (d-c) + c;
}
float Pulse(float x) {
  return pow(4.0 * x * (1.0 - x), 16.0);
}
void main()
{
  vec2 uv = v_uv0.xy;
  vec4 col = texture(texture, uv) * v_color;
  float alpha = col.a;
  float offset = Remap(-1., 1., 0., 0.2, sin(cc_time.x * 2.0 * 3.141592653589793 + uv.y * 3.0));
  float outlineWidth = 0.3 + offset * (uv.y);
  float centerAlpha = 0.5;
  float alphaDist = abs(alpha - centerAlpha);
  float mask = smoothstep(outlineWidth, 0., alphaDist);
  vec4 outlineColor = vec4(1., 0.5, 0., mask);
  float brightness = 0.3;
  outlineColor.rgb += Pulse((alphaDist + 0.5)) * brightness;
  col.a = smoothstep(0.48, 0.49, alpha);
  col.rgb *= col.a;
  col = mix(outlineColor, col, smoothstep(0.49, 0.5, alpha));
  gl_FragColor = col;
}

